import flwr as flimport torchfrom torch.utils.data import DataLoaderfrom dataset import load_mnist, get_client_datafrom client import FlowerClientfrom flwr.common import Context#Aggregation functiondef weighted_average(metrics):       accuracies = [num_examples * m["accuracy"]                   for num_examples, m in metrics]    total      = [num_examples                   for num_examples, _ in metrics]    return {"accuracy": sum(accuracies) / sum(total)}def run_FL(num_clients=10, num_rounds=30):        #loading all the data into server so it could simulate 10 clients itself    trainset, testset = load_mnist()    testloader = DataLoader(testset, batch_size=32)        #Creates client here    #sends client_id to dataset file get_client_data()        def client_fn(context: Context):                 client_id   = int(context.node_config["partition-id"])        trainloader = get_client_data(trainset, client_id, num_clients)                #Flower stores this and calls fit() and evaluate() on it during each round.                       return FlowerClient(client_id, trainloader, testloader).to_client()    #FedAvg strategy     strategy = fl.server.strategy.FedAvg(                fraction_fit=1.0,          #use 100% of clients each round        fraction_evaluate=1.0,     #evaluate on all clients        min_fit_clients=num_clients,    #check if everyone available        min_evaluate_clients=num_clients,            min_available_clients=num_clients,        evaluate_metrics_aggregation_fn=weighted_average,                    )    # Telling FLower to Run simulation and required details    history = fl.simulation.start_simulation(                client_fn=client_fn,        num_clients=num_clients,        config=fl.server.ServerConfig(num_rounds=num_rounds),         strategy=strategy,        client_resources={"num_cpus": 1},        actor_kwargs={"on_actor_init_fn": None},         ray_init_args={"ignore_reinit_error": True},    )    #logs everything    return history#only runs if server.py is directly executedif __name__ == "__main__":        history = run_FL(num_clients=10, num_rounds=5)        # Start with 5 rounds to verify everything works    # Scale to 30 once confirmed        print("\nRound-by-round accuracy:")    for round_num, metrics in enumerate(history.metrics_distributed['accuracy']):        print(f"  Round {round_num + 1}: {metrics[1]:.4f}")